import React, { useState, useRef } from 'react';
import { classifyCropImage } from '../services/geminiService';
import { DetectionResult } from '../types';

interface ImageScannerProps {
  onScanComplete: (result: DetectionResult, imageUrl: string) => void;
}

const ImageScanner: React.FC<ImageScannerProps> = ({ onScanComplete }) => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleScan = async () => {
    if (!selectedImage) return;

    setIsScanning(true);
    setError(null);
    try {
      const base64Data = selectedImage.split(',')[1];
      const result = await classifyCropImage(base64Data);
      onScanComplete(result, selectedImage);
    } catch (err) {
      console.error(err);
      setError("Failed to analyze image. Please try a clearer photo or check your connection.");
    } finally {
      setIsScanning(false);
    }
  };

  const resetScanner = () => {
    setSelectedImage(null);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl border border-slate-100 p-6 md:p-8">
      <div className="mb-6 text-center">
        <h2 className="text-2xl font-bold text-slate-800">Identify Leaf Diseases</h2>
        <p className="text-slate-500 mt-2">Upload a clear photo of a single crop leaf for AI diagnosis.</p>
      </div>

      {!selectedImage ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="border-2 border-dashed border-slate-300 rounded-xl p-12 flex flex-col items-center justify-center cursor-pointer hover:border-emerald-500 hover:bg-emerald-50 transition-all"
        >
          <div className="w-16 h-16 bg-emerald-100 rounded-full flex items-center justify-center text-emerald-600 mb-4">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg>
          </div>
          <p className="text-slate-600 font-medium text-lg">Click or tap to upload leaf image</p>
          <p className="text-slate-400 text-sm mt-1">Supports JPG, PNG (Max 5MB)</p>
          <input 
            type="file" 
            className="hidden" 
            ref={fileInputRef} 
            accept="image/*" 
            onChange={handleFileChange}
          />
        </div>
      ) : (
        <div className="space-y-6">
          <div className="relative group max-w-md mx-auto overflow-hidden rounded-xl shadow-inner bg-slate-100">
            <img 
              src={selectedImage} 
              alt="Leaf to scan" 
              className="w-full h-auto object-contain max-h-[400px]" 
            />
            {!isScanning && (
              <button 
                onClick={resetScanner}
                className="absolute top-2 right-2 bg-white/90 text-slate-800 p-2 rounded-full shadow-lg hover:bg-white"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            )}
          </div>

          {error && (
            <div className="bg-red-50 text-red-600 p-4 rounded-lg flex items-center gap-3">
              <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd"></path></svg>
              <p className="text-sm font-medium">{error}</p>
            </div>
          )}

          <div className="flex justify-center">
            <button
              onClick={handleScan}
              disabled={isScanning}
              className={`
                px-10 py-4 rounded-xl font-bold text-white shadow-lg transition-all flex items-center gap-3
                ${isScanning ? 'bg-slate-400 cursor-not-allowed' : 'bg-emerald-600 hover:bg-emerald-700 active:scale-95'}
              `}
            >
              {isScanning ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                  Scanning Plant Village Data...
                </>
              ) : (
                <>
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                  Identify Condition
                </>
              )}
            </button>
          </div>
        </div>
      )}

      <div className="mt-8 border-t pt-6 grid grid-cols-1 md:grid-cols-3 gap-4">
        {[
          { title: "AI Diagnosis", desc: "Using Gemini Vision", icon: "🤖" },
          { title: "Plant Village", desc: "38 distinct classes", icon: "🌱" },
          { title: "Instant Reports", desc: "Treatment plans included", icon: "📋" }
        ].map((item, i) => (
          <div key={i} className="flex items-center gap-3 bg-slate-50 p-3 rounded-lg border border-slate-100">
            <span className="text-2xl">{item.icon}</span>
            <div>
              <p className="text-xs font-bold text-slate-800 uppercase tracking-wider">{item.title}</p>
              <p className="text-xs text-slate-500">{item.desc}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ImageScanner;

import React from 'react';
import { HistoryItem } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

interface AnalysisDashboardProps {
  history: HistoryItem[];
}

const AnalysisDashboard: React.FC<AnalysisDashboardProps> = ({ history }) => {
  const getStats = () => {
    const crops: Record<string, number> = {};
    const diseases: Record<string, number> = {};

    history.forEach(h => {
      crops[h.crop] = (crops[h.crop] || 0) + 1;
      diseases[h.disease] = (diseases[h.disease] || 0) + 1;
    });

    const cropData = Object.entries(crops).map(([name, value]) => ({ name, value }));
    const diseaseData = Object.entries(diseases).map(([name, value]) => ({ name, value }));

    return { cropData, diseaseData };
  };

  const { cropData, diseaseData } = getStats();
  const COLORS = ['#059669', '#10b981', '#34d399', '#6ee7b7', '#a7f3d0'];

  if (history.length === 0) {
    return (
      <div className="bg-white rounded-2xl p-12 text-center border border-dashed border-slate-300">
        <div className="text-5xl mb-4">📊</div>
        <h3 className="text-lg font-bold text-slate-800">No data available yet</h3>
        <p className="text-slate-500 max-w-xs mx-auto">Start scanning your crops to see insights and trends in your farm's health.</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Crops Scanned</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={cropData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" fontSize={12} tick={{fill: '#64748b'}} />
                <YAxis fontSize={12} tick={{fill: '#64748b'}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  cursor={{ fill: '#f8fafc' }}
                />
                <Bar dataKey="value" fill="#10b981" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-4">Common Issues</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={diseaseData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {diseaseData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
          <h3 className="font-bold text-slate-800">Scan History</h3>
          <span className="text-xs bg-slate-100 px-2 py-1 rounded-full text-slate-600 font-medium">{history.length} scans</span>
        </div>
        <div className="divide-y divide-slate-100 max-h-[500px] overflow-y-auto">
          {history.slice().reverse().map((item) => (
            <div key={item.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 transition-colors">
              <img src={item.imageUrl} alt={item.crop} className="w-16 h-16 rounded-lg object-cover shadow-sm bg-slate-100" />
              <div className="flex-1">
                <div className="flex justify-between items-start">
                  <h4 className="font-bold text-slate-800">{item.crop}</h4>
                  <span className="text-[10px] text-slate-400 font-medium">{new Date(item.timestamp).toLocaleDateString()}</span>
                </div>
                <p className={`text-sm ${item.disease === 'Healthy' ? 'text-emerald-600' : 'text-amber-600'} font-medium`}>
                  {item.disease}
                </p>
                <div className="flex items-center gap-2 mt-1">
                  <div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
                    <div className="bg-emerald-500 h-full" style={{ width: `${item.confidence}%` }}></div>
                  </div>
                  <span className="text-[10px] text-slate-400 whitespace-nowrap">{item.confidence}% Match</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default AnalysisDashboard;

