import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import ImageScanner from './components/ImageScanner';
import AnalysisDashboard from './components/AnalysisDashboard';
import DiseaseLibrary from './components/DiseaseLibrary';
import { DetectionResult, HistoryItem } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'scanner' | 'dashboard' | 'library'>('scanner');
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [currentResult, setCurrentResult] = useState<DetectionResult | null>(null);
  const [showResultModal, setShowResultModal] = useState(false);

  // Load history from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('agrishield_history');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load history", e);
      }
    }
  }, []);

  const handleScanComplete = (result: DetectionResult, imageUrl: string) => {
    const newItem: HistoryItem = {
      ...result,
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      imageUrl
    };

    const newHistory = [newItem, ...history];
    setHistory(newHistory);
    localStorage.setItem('agrishield_history', JSON.stringify(newHistory));

    setCurrentResult(result);
    setShowResultModal(true);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar activeTab={activeTab} onTabChange={setActiveTab} />

      <main className="flex-grow max-w-5xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 md:py-12">
        {activeTab === 'scanner' && (
          <div className="max-w-3xl mx-auto space-y-12">
            <header className="text-center space-y-4">
              <span className="inline-block px-3 py-1 bg-emerald-100 text-emerald-700 text-xs font-bold rounded-full uppercase tracking-wider">
                Powered by Gemini Vision
              </span>
              <h1 className="text-4xl md:text-5xl font-extrabold text-slate-900 tracking-tight">
                Secure Your Harvest <br/>with <span className="text-emerald-600">Smart AI</span>
              </h1>
              <p className="text-slate-500 text-lg max-w-xl mx-auto">
                Advanced crop disease detection using image classification models trained on the massive Plant Village dataset.
              </p>
            </header>

            <ImageScanner onScanComplete={handleScanComplete} />
          </div>
        )}

        {activeTab === 'dashboard' && <AnalysisDashboard history={history} />}

        {activeTab === 'library' && <DiseaseLibrary />}
      </main>

      <footer className="bg-white border-t border-slate-200 py-8">
        <div className="max-w-5xl mx-auto px-4 text-center">
          <p className="text-slate-400 text-sm">
            © 2024 AgriShield AI Design Project. Developed for 5CS1990 Module.
          </p>
        </div>
      </footer>

      {/* Result Modal */}
      {showResultModal && currentResult && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-3xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl relative">
            <button 
              onClick={() => setShowResultModal(false)}
              className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 p-2"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
            </button>

            <div className="p-8">
              <div className="flex items-center gap-4 mb-6">
                <div className={`w-16 h-16 rounded-2xl flex items-center justify-center text-3xl shadow-lg ${currentResult.disease === 'Healthy' ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'}`}>
                  {currentResult.disease === 'Healthy' ? '🌿' : '⚠️'}
                </div>
                <div>
                  <h2 className="text-2xl font-bold text-slate-900">{currentResult.crop}</h2>
                  <p className={`text-lg font-medium ${currentResult.disease === 'Healthy' ? 'text-emerald-600' : 'text-amber-600'}`}>
                    {currentResult.disease}
                  </p>
