import React, { useState, useRef } from 'react';
import { classifyCropImage } from '../services/geminiService';
import { DetectionResult } from '../types';

interface ImageScannerProps {
  onScanComplete: (result: DetectionResult, imageUrl: string) => void;
}

const ImageScanner: React.FC<ImageScannerProps> = ({ onScanComplete }) => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleScan = async () => {
    if (!selectedImage) return;
    setIsScanning(true);
    setError(null);
    try {
      const base64Data = selectedImage.split(',')[1];
      const result = await classifyCropImage(base64Data);
      onScanComplete(result, selectedImage);
    } catch (err) {
      console.error(err);
      setError("Vision model analysis failed. Please try again with better lighting.");
    } finally {
      setIsScanning(false);
    }
  };

  const resetScanner = () => {
    setSelectedImage(null);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = "";
  };

  return (
    <div className="bg-white rounded-[32px] shadow-2xl shadow-slate-200/50 border border-slate-100 p-8 md:p-10 transition-all">
      {!selectedImage ? (
        <div 
          onClick={() => fileInputRef.current?.click()}
          className="group relative border-2 border-dashed border-slate-200 rounded-[24px] p-16 flex flex-col items-center justify-center cursor-pointer hover:border-emerald-400 hover:bg-emerald-50/30 transition-all animate-pulse-border"
        >
          <div className="w-20 h-20 bg-emerald-100/50 rounded-full flex items-center justify-center text-emerald-600 mb-6 group-hover:scale-110 transition-transform duration-500">
            <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
          </div>
          <h3 className="text-xl font-bold text-slate-800 mb-2">Drop leaf image here</h3>
          <p className="text-slate-400 text-sm font-medium">Capture a clear top-down view for best accuracy</p>
          <input 
            type="file" 
            className="hidden" 
            ref={fileInputRef} 
            accept="image/*" 
            onChange={handleFileChange}
          />
        </div>
      ) : (
        <div className="space-y-8 animate-in fade-in zoom-in duration-500">
          <div className="relative mx-auto group">
            <div className="absolute -inset-1 bg-gradient-to-r from-emerald-500 to-lime-400 rounded-[26px] blur opacity-25 group-hover:opacity-40 transition duration-1000"></div>
            <div className="relative overflow-hidden rounded-[24px] shadow-xl bg-slate-100 aspect-square md:aspect-video flex items-center justify-center">
              <img 
                src={selectedImage} 
                alt="Leaf scan" 
                className="w-full h-full object-cover" 
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent"></div>
              {isScanning && (
                <div className="absolute inset-0 bg-emerald-900/40 backdrop-blur-[2px] flex flex-col items-center justify-center text-white p-6">
                  <div className="w-12 h-12 border-4 border-emerald-400 border-t-transparent rounded-full animate-spin mb-4"></div>
                  <p className="font-bold text-lg tracking-tight">Analyzing Pathology...</p>
                  <p className="text-emerald-100 text-xs mt-1 uppercase tracking-widest font-bold">Plant Village Model 2.0</p>
                </div>
              )}
            </div>

            {!isScanning && (
              <button 
                onClick={resetScanner}
                className="absolute top-4 right-4 bg-white/90 hover:bg-white text-slate-800 p-2.5 rounded-full shadow-xl transition-all active:scale-90"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            )}
          </div>

          <div className="flex flex-col items-center gap-4">
            <button
              onClick={handleScan}
              disabled={isScanning}
              className={`
                group px-12 py-5 rounded-[20px] font-extrabold text-white shadow-xl shadow-emerald-200 transition-all flex items-center gap-3 active:scale-95
                ${isScanning ? 'bg-slate-300 shadow-none' : 'bg-gradient-to-r from-emerald-600 to-emerald-500 hover:shadow-emerald-300 hover:-translate-y-1'}
              `}
            >
              {isScanning ? 'Processing Intelligence...' : 'Initiate AI Diagnosis'}
              {!isScanning && <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>}
            </button>
            {error && <p className="text-red-500 text-sm font-bold animate-bounce">{error}</p>}
          </div>
        </div>
      )}

      <div className="mt-12 grid grid-cols-1 sm:grid-cols-3 gap-6">
        {[
          { title: "Deep Learning", desc: "Vision Transformer", icon: "🧠" },
          { title: "Kaggle Verified", desc: "Plant Village Data", icon: "💎" },
          { title: "Treatment Plan", desc: "Actionable Advice", icon: "🩹" }
        ].map((item, i) => (
          <div key={i} className="flex items-center gap-4 p-5 rounded-2xl bg-slate-50 border border-slate-100 group hover:bg-white hover:shadow-md transition-all">
            <span className="text-2xl group-hover:scale-125 transition-transform">{item.icon}</span>
            <div>
              <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">{item.title}</p>
              <p className="text-xs font-bold text-slate-800">{item.desc}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ImageScanner;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import ImageScanner from './components/ImageScanner';
import AnalysisDashboard from './components/AnalysisDashboard';
import DiseaseLibrary from './components/DiseaseLibrary';
import { DetectionResult, HistoryItem } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'scanner' | 'dashboard' | 'library'>('scanner');
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [currentResult, setCurrentResult] = useState<DetectionResult | null>(null);
  const [showResultModal, setShowResultModal] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('agrishield_history');
    if (saved) {
      try { setHistory(JSON.parse(saved)); } catch (e) { console.error(e); }
    }
  }, []);

  const handleScanComplete = (result: DetectionResult, imageUrl: string) => {
    const newItem: HistoryItem = { ...result, id: crypto.randomUUID(), timestamp: Date.now(), imageUrl };
    const newHistory = [newItem, ...history];
    setHistory(newHistory);
    localStorage.setItem('agrishield_history', JSON.stringify(newHistory));
    setCurrentResult(result);
    setShowResultModal(true);
  };

  return (
    <div className="min-h-screen relative pb-20">
      {/* Decorative background elements */}
      <div className="blob top-0 left-[-100px] opacity-40"></div>
      <div className="blob bottom-0 right-[-100px] opacity-30 bg-emerald-200"></div>

      <Navbar activeTab={activeTab} onTabChange={setActiveTab} />

      <main className="max-w-5xl mx-auto px-4 pt-32 sm:px-6 lg:px-8">
